class Node:
 def __init__(self, data):
 self.data = data
 self.next = None

def insert_at_beginning(head, data):
 new_node = Node(data)
 new_node.next = head
 return new_node

typedef struct Node {
 int data;
 struct Node* next;
} Node;

Node* insert_at_beginning(Node* head, int data) {
 Node* new_node = (Node*)malloc(sizeof(Node));
 new_node->data = data;
 new_node->next = head;
 return new_node;
}

public class Node {
 int data;
 Node next;

 public Node(int data) {
 this.data = data;
 this.next = null;
 }
}

public Node insertAtBeginning(Node head, int data) {
 Node newNode = new Node(data);
 newNode.next = head;
 return newNode;
}
